class Solution:
    def gardenNoAdj(self, n: int, paths: List[List[int]]) -> List[int]:
        graph = [[] for _ in range(n + 1)]
        for x, y in paths:
            graph[x].append(y)
            graph[y].append(x)
        res = [0] * (n + 1)
        for i in range(1, n + 1):
            used = set()
            for j in graph[i]:
                if res[j] != 0:
                    used.add(res[j])
            for k in range(1, 5):
                if k not in used:
                    res[i] = k
                    break
        return res[1:]
